def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
        else:
            ratio = item / capacity
            total_penalty = 0
            if ratio < 0.3:
                for k in range(1, 5):
                    factor = (ratio ** k) * (5 - k)
                    total_penalty += factor
                priorities[i] = max(0, 15 - total_penalty * 7)
            elif 0.3 <= ratio < 0.7:
                weighted_sum = 0
                count = 0
                for step in np.linspace(0.3, 0.7, num=10):
                    val = np.sin(ratio * step * np.pi) + np.log1p(ratio / (step + 0.1))
                    weighted_sum += val
                    count += 1
                avg = weighted_sum / count
                priorities[i] = avg * 12
            elif 0.7 <= ratio <= 1:
                base = np.exp(-5 * (1 - ratio) ** 2) * 20
                adjust = 0
                for x in range(1, int(np.ceil(capacity))):
                    if (x + int(item)) % 3 == 0:
                        adjust += x / (x + ratio)
                priorities[i] = base + adjust
            else:
                penalty = 0
                for d in range(1, int(ratio) + 1):
                    if int(ratio * 100) % (d * 10) == 0:
                        penalty += d * 3
                large_penalty = (ratio - 1) ** 3 * 50
                priorities[i] = penalty + large_penalty
            if priorities[i] < 0:
                priorities[i] = 0
    finite_mask = np.isfinite(priorities)
    if np.any(finite_mask):
        min_priority = np.min(priorities[finite_mask])
    else:
        min_priority = 0
    priorities = np.where(finite_mask, priorities, min_priority + 200)
    return priorities
